"use strict";(globalThis.webpackChunksite=globalThis.webpackChunksite||[]).push([[849],{6164:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"mainSidebar":[{"type":"category","label":"Python","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Python/Welcome","label":"Welcome!","docId":"Python/Welcome","unlisted":false},{"type":"category","label":"Getting Started","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Python/Getting Started/Creating Your First Plugin","label":"Creating Your First Plugin","docId":"Python/Getting Started/Creating Your First Plugin","unlisted":false},{"type":"link","href":"/docs/Python/Getting Started/Setting up a Development Environment","label":"Setting up a Development Environment","docId":"Python/Getting Started/Setting up a Development Environment","unlisted":false}]},{"type":"category","label":"Plugin Framework","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Python/Plugin Framework/Settings","label":"Settings","docId":"Python/Plugin Framework/Settings","unlisted":false},{"type":"link","href":"/docs/Python/Plugin Framework/User Interface","label":"User Interface","docId":"Python/Plugin Framework/User Interface","unlisted":false},{"type":"link","href":"/docs/Python/Plugin Framework/Events","label":"Events","docId":"Python/Plugin Framework/Events","unlisted":false},{"type":"link","href":"/docs/Python/Plugin Framework/Plugin Catalogue","label":"Plugin Catalogue","docId":"Python/Plugin Framework/Plugin Catalogue","unlisted":false}]},{"type":"category","label":"Modules","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Python/Modules/Camera","label":"Camera","docId":"Python/Modules/Camera","unlisted":false},{"type":"link","href":"/docs/Python/Modules/SDKController","label":"SDKController","docId":"Python/Modules/SDKController","unlisted":false},{"type":"link","href":"/docs/Python/Modules/TruckSimAPI","label":"TruckSimAPI","docId":"Python/Modules/TruckSimAPI","unlisted":false}]},{"type":"category","label":"Existing Plugins","collapsible":true,"collapsed":true,"items":[{"type":"category","label":"Map","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Python/Existing Plugins/Map/Extracting Map Data","label":"Extracting Map Data","docId":"Python/Existing Plugins/Map/Extracting Map Data","unlisted":false}]},{"type":"category","label":"AR\xa0","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Python/Existing Plugins/AR\xa0/Explanation","label":"Explanation","docId":"Python/Existing Plugins/AR\xa0/Explanation","unlisted":false},{"type":"link","href":"/docs/Python/Existing Plugins/AR\xa0/Classes","label":"Classes","docId":"Python/Existing Plugins/AR\xa0/Classes","unlisted":false}]}]}]},{"type":"category","label":"Rewrite","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Rewrite/Introduction","label":"1. Introduction","docId":"Rewrite/Introduction","unlisted":false},{"type":"link","href":"/docs/Rewrite/PluginLoading","label":"2. How ETS2LA loads plugins","docId":"Rewrite/PluginLoading","unlisted":false},{"type":"link","href":"/docs/Rewrite/Events","label":"3. The Event System","docId":"Rewrite/Events","unlisted":false},{"type":"link","href":"/docs/Rewrite/Settings","label":"4. Settings","docId":"Rewrite/Settings","unlisted":false},{"type":"link","href":"/docs/Rewrite/UserInput","label":"5. Gathering user input","docId":"Rewrite/UserInput","unlisted":false}]}]},"docs":{"Python/Existing Plugins/AR\xa0/Classes":{"id":"Python/Existing Plugins/AR\xa0/Classes","title":"Classes","description":"These first classes are the root classes used by the elements. If you are looking for the actual elements then please scroll down a bit to the _Main AR Elements_ header.","sidebar":"mainSidebar"},"Python/Existing Plugins/AR\xa0/Explanation":{"id":"Python/Existing Plugins/AR\xa0/Explanation","title":"Explanation","description":"The AR plugin provides an overlay on top of the game. This overlay contains all the code required to convert 3D coordinates into the game world. The API for this plugin is made to be as easy to use as possible for 3rd party developers.","sidebar":"mainSidebar"},"Python/Existing Plugins/Map/Extracting Map Data":{"id":"Python/Existing Plugins/Map/Extracting Map Data","title":"Extracting Map Data","description":"This page will walk you through extracting additional Map data for ETS2LA. Please keep in mind that this is an advanced procedure that should only be attempted if you\'re confortable with a terminal and have at least some linux knowledge!","sidebar":"mainSidebar"},"Python/Getting Started/Creating Your First Plugin":{"id":"Python/Getting Started/Creating Your First Plugin","title":"Creating Your First Plugin","description":"This is actually really easy! The entire framework has been made to make the initial setup as painless as possible. We should get you up and running in around 15 - 30 minutes!","sidebar":"mainSidebar"},"Python/Getting Started/Setting up a Development Environment":{"id":"Python/Getting Started/Setting up a Development Environment","title":"Setting up a Development Environment","description":"While it is technically possible to develop for ETS2LA using the release environment via the installer, it is recommended to directly clone the program from GitHub. These instructions will get you up and running in this regard.","sidebar":"mainSidebar"},"Python/Modules/Camera":{"id":"Python/Modules/Camera","title":"Camera","description":"This module will output the current camera characteristics that our plugin extracts from the game. You can find the plugin code on gitlab.","sidebar":"mainSidebar"},"Python/Modules/SDKController":{"id":"Python/Modules/SDKController","title":"SDKController","description":"This module is a bit different from a normal module. Instead of using the run() file it just provides an object to interface with the SDK. We will explore how this works here!","sidebar":"mainSidebar"},"Python/Modules/TruckSimAPI":{"id":"Python/Modules/TruckSimAPI","title":"TruckSimAPI","description":"This module will provide information from the in game API. This is the same API that most other applications use as well.","sidebar":"mainSidebar"},"Python/Plugin Framework/Events":{"id":"Python/Plugin Framework/Events","title":"Events","description":"An excellent way to handle communications between plugins, in addition to tags, is using the ETS2LA event system. While tags are more focused on sending large amounts of data, you can use the event system to send relatively small amounts of information very easily.","sidebar":"mainSidebar"},"Python/Plugin Framework/Plugin Catalogue":{"id":"Python/Plugin Framework/Plugin Catalogue","title":"Plugin Catalogue","description":"ETS2LA uses a central plugin catalogue. This means that once you\'ve created your plugin, you can make a PR to the plugin catalogue describing your changes. If that PR is accepted, then your plugin will be visible to all ETS2LA users.","sidebar":"mainSidebar"},"Python/Plugin Framework/Settings":{"id":"Python/Plugin Framework/Settings","title":"Settings","description":"ETS2LA has a built in settings framework that handles race conditions between all the different processes. When accessing ETS2LA settings do NOT use anything outside of the official framework. You can still create custom settings files, but make sure these will only ever be changed by a single process at a time.","sidebar":"mainSidebar"},"Python/Plugin Framework/User Interface":{"id":"Python/Plugin Framework/User Interface","title":"User Interface","description":"ETS2LA has a built in custom UI framework. It functions much like NextJS and it\'s SSR (Server Side Rendering). This means that you create components, that get rendered by the backend, and then sent over to the frontend to be displayed. This has some limitations, but it provides a very fast and flexible way for developers to create UI, you can use any CSS you wish!","sidebar":"mainSidebar"},"Python/Welcome":{"id":"Python/Welcome","title":"Welcome!","description":"These pages have been written to document the ETS2LA framework and plugins so that other developers have the option of working with us. Please note that some pages here might be slightly out of date due to the speed of development.","sidebar":"mainSidebar"},"Rewrite/Events":{"id":"Rewrite/Events","title":"The Event System","description":"Now we\'re getting to our first library, ETS2LA.Backend.Events.","sidebar":"mainSidebar"},"Rewrite/Introduction":{"id":"Rewrite/Introduction","title":"Introduction","description":"We\'ve fundamentally changed how ETS2LA works with the (upcoming) release of C#. To ease the transition this page will first describe some of the core concepts of how ETS2LA works, and how some things are done.","sidebar":"mainSidebar"},"Rewrite/PluginLoading":{"id":"Rewrite/PluginLoading","title":"How ETS2LA loads plugins","description":"We provide a recommended starting point on our GitHub. Even though using it is not strictly necessary it is highly recommended.","sidebar":"mainSidebar"},"Rewrite/Settings":{"id":"Rewrite/Settings","title":"Settings","description":"Much like with events, ETS2LA provides a built in way to handle settings. This is done via a SettingsHandler() class with your custom settings struct.","sidebar":"mainSidebar"},"Rewrite/UserInput":{"id":"Rewrite/UserInput","title":"Gathering user input","description":"This is one of the most important features of ETS2LA, and it\'s also the one that you must use instead of 3rd party libraries. ETS2LA provides a built in way to gather user input, and it\'s the only way that is guaranteed to work across all plugins, features and platforms. We handle the transitions between Linux and Windows, use our API or be square!","sidebar":"mainSidebar"}}}}')}}]);